        if (invert) {
            long invN = modPow(n, MOD - 2, MOD);
            for (int i = 0; i < n; i++) a[i] = a[i] * invN % MOD;
        }
    }

    public static int[] ntt(int[] data) {
        int idx = 0;
        int na = data[idx++];
        long[] a = new long[na];
        for (int i = 0; i < na; i++) a[i] = ((long) data[idx++] % MOD + MOD) % MOD;
        int nb = data[idx++];
